// If all common segments have equal scores, then consider length and specificity
if (a.scores.length !== b.scores.length) {
  // Prefer routes with a longer shared prefix before they diverge.
  // This ensures that `/admin-levels/{-$id}/reports` outranks
  // `/admin-levels/$id` when matching `/admin-levels/reports`.
  // (The former has 2 common segments, the latter only 1.)
  if (a.parsed.length !== b.parsed.length) {
    const minParsedLength = Math.min(a.parsed.length, b.parsed.length)
    let commonPrefixLength = 0
    for (let i = 0; i < minParsedLength; i++) {
      if (a.parsed[i]!.value !== b.parsed[i]!.value) break
      commonPrefixLength++
    }

    const aHasExtraSegments = a.parsed.length > commonPrefixLength
    const bHasExtraSegments = b.parsed.length > commonPrefixLength

    // If one route is a strict prefix of the other, the longer one is more specific
    if (aHasExtraSegments !== bHasExtraSegments) {
      return aHasExtraSegments ? -1 : 1
    }
  }

  // Count optional parameters in each route
  const aOptionalCount = a.parsed.filter(
    (seg) => seg.type === 'optional-param',
  ).length
  const bOptionalCount = b.parsed.filter(
    (seg) => seg.type === 'optional-param',
  ).length

  // If different number of optional parameters, fewer optional parameters wins (more specific)
  if (aOptionalCount !== bOptionalCount) {
    return aOptionalCount - bOptionalCount
  }

  // If same number of optional parameters, longer path wins (for static segments)
  return b.scores.length - a.scores.length
}

