import { last } from './utils'
import type { MatchLocation } from './RouterProvider'
import type { AnyPathParams } from './route'

export interface Segment {
  type: 'pathname' | 'param' | 'wildcard' | 'optional-param'
  value: string
  prefixSegment?: string
  suffixSegment?: string
}

export function joinPaths(paths: Array<string | undefined>) {
  return cleanPath(
    paths
      .filter((val) => {
        return val !== undefined
      })
      .join('/'),
  )
}

export function cleanPath(path: string) {
  // remove double slashes
  return path.replace(/\/{2,}/g, '/')
}

export function trimPathLeft(path: string) {
  return path === '/' ? path : path.replace(/^\/{1,}/, '')
}

export function trimPathRight(path: string) {
  return path === '/' ? path : path.replace(/\/{1,}$/, '')
}

export function trimPath(path: string) {
  return trimPathRight(trimPathLeft(path))
}

export function removeTrailingSlash(value: string, basepath: string): string {
  if (value?.endsWith('/') && value !== '/' && value !== `${basepath}/`) {
    return value.slice(0, -1)
  }
  return value
}

// intended to only compare path name
// see the usage in the isActive under useLinkProps
// /sample/path1 = /sample/path1/
// /sample/path1/some <> /sample/path1
export function exactPathTest(
  pathName1: string,
  pathName2: string,
  basepath: string,
): boolean {
  return (
    removeTrailingSlash(pathName1, basepath) ===
    removeTrailingSlash(pathName2, basepath)
  )
}

// When resolving relative paths, we treat all paths as if they are trailing slash
// documents. All trailing slashes are removed after the path is resolved.
// Here are a few examples:
//
// /a/b/c + ./d = /a/b/c/d
// /a/b/c + ../d = /a/b/d
// /a/b/c + ./d/ = /a/b/c/d
// /a/b/c + ../d/ = /a/b/d
// /a/b/c + ./ = /a/b/c
//
// Absolute paths that start with `/` short circuit the resolution process to the root
// path.
//
// Here are some examples:
//
// /a/b/c + /d = /d
// /a/b/c + /d/ = /d
// /a/b/c + / = /
//
// Non-.-prefixed paths are still treated as relative paths, resolved like `./`
//
// Here are some examples:
//
// /a/b/c + d = /a/b/c/d
// /a/b/c + d/ = /a/b/c/d
// /a/b/c + d/e = /a/b/c/d/e
interface ResolvePathOptions {
  basepath: string
  base: string
  to: string
  trailingSlash?: 'always' | 'never' | 'preserve'
  caseSensitive?: boolean
}

export function resolvePath({
  basepath,
  base,
  to,
  trailingSlash = 'never',
  caseSensitive,
}: ResolvePathOptions) {
  base = removeBasepath(basepath, base, caseSensitive)
  to = removeBasepath(basepath, to, caseSensitive)

  let baseSegments = parsePathname(base)
  const toSegments = parsePathname(to)

  if (baseSegments.length > 1 && last(baseSegments)?.value === '/') {
    baseSegments.pop()
  }

  toSegments.forEach((toSegment, index) => {
    if (toSegment.value === '/') {
      if (!index) {
        // Leading slash
        baseSegments = [toSegment]
      } else if (index === toSegments.length - 1) {
        // Trailing Slash
        baseSegments.push(toSegment)
      } else {
        // ignore inter-slashes
      }
    } else if (toSegment.value === '..') {
      baseSegments.pop()
    } else if (toSegment.value === '.') {
      // ignore
    } else {
      baseSegments.push(toSegment)
    }
  })

  if (baseSegments.length > 1) {
    if (last(baseSegments)?.value === '/') {
      if (trailingSlash === 'never') {
        baseSegments.pop()
      }
    } else if (trailingSlash === 'always') {
      baseSegments.push({ type: 'pathname', value: '/' })
    }
  }

  const segmentValues = baseSegments.map((segment) => {
    if (segment.type === 'param') {
      const param = segment.value.substring(1)
      if (segment.prefixSegment && segment.suffixSegment) {
        return `${segment.prefixSegment}{$${param}}${segment.suffixSegment}`
      } else if (segment.prefixSegment) {
        return `${segment.prefixSegment}{$${param}}`
      } else if (segment.suffixSegment) {
        return `{$${param}}${segment.suffixSegment}`
      }
    }
    if (segment.type === 'optional-param') {
      const param = segment.value.substring(1)
      if (segment.prefixSegment && segment.suffixSegment) {
        return `${segment.prefixSegment}{-$${param}}${segment.suffixSegment}`
      } else if (segment.prefixSegment) {
        return `${segment.prefixSegment}{-$${param}}`
      } else if (segment.suffixSegment) {
        return `{-$${param}}${segment.suffixSegment}`
      }
      return `{-$${param}}`
    }

    if (segment.type === 'wildcard') {
      if (segment.prefixSegment && segment.suffixSegment) {
        return `${segment.prefixSegment}{$}${segment.suffixSegment}`
      } else if (segment.prefixSegment) {
        return `${segment.prefixSegment}{$}`
      } else if (segment.suffixSegment) {
        return `{$}${segment.suffixSegment}`
      }
    }
    return segment.value
  })
  const joined = joinPaths([basepath, ...segmentValues])
  return cleanPath(joined)
}

const PARAM_RE = /^\$.{1,}$/ // $paramName
const PARAM_W_CURLY_BRACES_RE = /^(.*?)\{(\$[a-zA-Z_$][a-zA-Z0-9_$]*)\}(.*)$/ // prefix{$paramName}suffix
const OPTIONAL_PARAM_W_CURLY_BRACES_RE =
  /^(.*?)\{-(\$[a-zA-Z_$][a-zA-Z0-9_$]*)\}(.*)$/ // prefix{-$paramName}suffix

const WILDCARD_RE = /^\$$/ // $
const WILDCARD_W_CURLY_BRACES_RE = /^(.*?)\{\$\}(.*)$/ // prefix{$}suffix

/**
 * Required: `/foo/$bar` ✅
 * Prefix and Suffix: `/foo/prefix${bar}suffix` ✅
 * Wildcard: `/foo/$` ✅
 * Wildcard with Prefix and Suffix: `/foo/prefix{$}suffix` ✅
 *
 * Optional param: `/foo/{-$bar}`
 * Optional param with Prefix and Suffix: `/foo/prefix{-$bar}suffix`

 * Future:
 * Optional named segment: `/foo/{bar}`
 * Optional named segment with Prefix and Suffix: `/foo/prefix{-bar}suffix`
 * Escape special characters:
 * - `/foo/[$]` - Static route
 * - `/foo/[$]{$foo} - Dynamic route with a static prefix of `$`
 * - `/foo/{$foo}[$]` - Dynamic route with a static suffix of `$`
 */
export function parsePathname(pathname?: string): Array<Segment> {
  if (!pathname) {
    return []
  }

  pathname = cleanPath(pathname)

  const segments: Array<Segment> = []

  if (pathname.slice(0, 1) === '/') {
    pathname = pathname.substring(1)
    segments.push({
      type: 'pathname',
      value: '/',
    })
  }

  if (!pathname) {
    return segments
  }

  // Remove empty segments and '.' segments
  const split = pathname.split('/').filter(Boolean)

  segments.push(
    ...split.map((part): Segment => {
      // Check for wildcard with curly braces: prefix{$}suffix
      const wildcardBracesMatch = part.match(WILDCARD_W_CURLY_BRACES_RE)
      if (wildcardBracesMatch) {
        const prefix = wildcardBracesMatch[1]
        const suffix = wildcardBracesMatch[2]
        return {
          type: 'wildcard',
          value: '$',
          prefixSegment: prefix || undefined,
          suffixSegment: suffix || undefined,
        }
      }

      // Check for optional parameter format: prefix{-$paramName}suffix
      const optionalParamBracesMatch = part.match(
        OPTIONAL_PARAM_W_CURLY_BRACES_RE,
      )
      if (optionalParamBracesMatch) {
        const prefix = optionalParamBracesMatch[1]
        const paramName = optionalParamBracesMatch[2]!
        const suffix = optionalParamBracesMatch[3]
        return {
          type: 'optional-param',
          value: paramName, // Now just $paramName (no prefix)
          prefixSegment: prefix || undefined,
          suffixSegment: suffix || undefined,
        }
      }

      // Check for the new parameter format: prefix{$paramName}suffix
      const paramBracesMatch = part.match(PARAM_W_CURLY_BRACES_RE)
      if (paramBracesMatch) {
        const prefix = paramBracesMatch[1]
        const paramName = paramBracesMatch[2]
        const suffix = paramBracesMatch[3]
        return {
          type: 'param',
          value: '' + paramName,
          prefixSegment: prefix || undefined,
          suffixSegment: suffix || undefined,
        }
      }

      // Check for bare parameter format: $paramName (without curly braces)
      if (PARAM_RE.test(part)) {
        const paramName = part.substring(1)
        return {
          type: 'param',
          value: '$' + paramName,
          prefixSegment: undefined,
          suffixSegment: undefined,
        }
      }

      // Check for bare wildcard: $ (without curly braces)
      if (WILDCARD_RE.test(part)) {
        return {
          type: 'wildcard',
          value: '$',
          prefixSegment: undefined,
          suffixSegment: undefined,
        }
      }

      // Handle regular pathname segment
      return {
        type: 'pathname',
        value: part.includes('%25')
          ? part
              .split('%25')
              .map((segment) => decodeURI(segment))
              .join('%25')
          : decodeURI(part),
      }
    }),
  )

  if (pathname.slice(-1) === '/') {
    pathname = pathname.substring(1)
    segments.push({
      type: 'pathname',
      value: '/',
    })
  }

  return segments
}

interface InterpolatePathOptions {
  path?: string
  params: Record<string, unknown>
  leaveWildcards?: boolean
  leaveParams?: boolean
  // Map of encoded chars to decoded chars (e.g. '%40' -> '@') that should remain decoded in path params
  decodeCharMap?: Map<string, string>
}

type InterPolatePathResult = {
  interpolatedPath: string
  usedParams: Record<string, unknown>
  isMissingParams: boolean // true if any params were not available when being looked up in the params object
}
export function interpolatePath({
  path,
  params,
  leaveWildcards,
  leaveParams,
  decodeCharMap,
}: InterpolatePathOptions): InterPolatePathResult {
  const interpolatedPathSegments = parsePathname(path)

  function encodeParam(key: string): any {
    const value = params[key]
    const isValueString = typeof value === 'string'

    if (['*', '_splat'].includes(key)) {
      // the splat/catch-all routes shouldn't have the '/' encoded out
      return isValueString ? encodeURI(value) : value
    } else {
      return isValueString ? encodePathParam(value, decodeCharMap) : value
    }
  }

  // Tracking if any params are missing in the `params` object
  // when interpolating the path
  let isMissingParams = false

  const usedParams: Record<string, unknown> = {}
  const interpolatedPath = joinPaths(
    interpolatedPathSegments.map((segment) => {
      if (segment.type === 'wildcard') {
        usedParams._splat = params._splat
        const segmentPrefix = segment.prefixSegment || ''
        const segmentSuffix = segment.suffixSegment || ''

        // Check if _splat parameter is missing
        if (!('_splat' in params)) {
          isMissingParams = true
          // For missing splat parameters, just return the prefix and suffix without the wildcard
          if (leaveWildcards) {
            return `${segmentPrefix}${segment.value}${segmentSuffix}`
          }
          // If there is a prefix or suffix, return them joined, otherwise omit the segment
          if (segmentPrefix || segmentSuffix) {
            return `${segmentPrefix}${segmentSuffix}`
          }
          return undefined
        }

        const value = encodeParam('_splat')
        if (leaveWildcards) {
          return `${segmentPrefix}${segment.value}${value ?? ''}${segmentSuffix}`
        }
        return `${segmentPrefix}${value}${segmentSuffix}`
      }

      if (segment.type === 'param') {
        const key = segment.value.substring(1)
        if (!isMissingParams && !(key in params)) {
          isMissingParams = true
        }
        usedParams[key] = params[key]

        const segmentPrefix = segment.prefixSegment || ''
        const segmentSuffix = segment.suffixSegment || ''
        if (leaveParams) {
          const value = encodeParam(segment.value)
          return `${segmentPrefix}${segment.value}${value ?? ''}${segmentSuffix}`
        }
        return `${segmentPrefix}${encodeParam(key) ?? 'undefined'}${segmentSuffix}`
      }

      if (segment.type === 'optional-param') {
        const key = segment.value.substring(1)

        const segmentPrefix = segment.prefixSegment || ''
        const segmentSuffix = segment.suffixSegment || ''

        // Check if optional parameter is missing or undefined
        if (!(key in params) || params[key] == null) {
          // For optional params with prefix/suffix, keep the prefix/suffix but omit the param
          if (segmentPrefix || segmentSuffix) {
            return `${segmentPrefix}${segmentSuffix}`
          }
          // If no prefix/suffix, omit the entire segment
          return undefined
        }

        usedParams[key] = params[key]

        if (leaveParams) {
          const value = encodeParam(segment.value)
          return `${segmentPrefix}${segment.value}${value ?? ''}${segmentSuffix}`
        }
        return `${segmentPrefix}${encodeParam(key) ?? ''}${segmentSuffix}`
      }

      return segment.value
    }),
  )
  return { usedParams, interpolatedPath, isMissingParams }
}

function encodePathParam(value: string, decodeCharMap?: Map<string, string>) {
  let encoded = encodeURIComponent(value)
  if (decodeCharMap) {
    for (const [encodedChar, char] of decodeCharMap) {
      encoded = encoded.replaceAll(encodedChar, char)
    }
  }
  return encoded
}

export function matchPathname(
  basepath: string,
  currentPathname: string,
  matchLocation: Pick<MatchLocation, 'to' | 'fuzzy' | 'caseSensitive'>,
): AnyPathParams | undefined {
  const pathParams = matchByPath(basepath, currentPathname, matchLocation)
  // const searchMatched = matchBySearch(location.search, matchLocation)

  if (matchLocation.to && !pathParams) {
    return
  }

  return pathParams ?? {}
}

export function removeBasepath(
  basepath: string,
  pathname: string,
  caseSensitive: boolean = false,
) {
  // normalize basepath and pathname for case-insensitive comparison if needed
  const normalizedBasepath = caseSensitive ? basepath : basepath.toLowerCase()
  const normalizedPathname = caseSensitive ? pathname : pathname.toLowerCase()

  switch (true) {
    // default behaviour is to serve app from the root - pathname
    // left untouched
    case normalizedBasepath === '/':
      return pathname

    // shortcut for removing the basepath if it matches the pathname
    case normalizedPathname === normalizedBasepath:
      return ''

    // in case pathname is shorter than basepath - there is
    // nothing to remove
    case pathname.length < basepath.length:
      return pathname

    // avoid matching partial segments - strict equality handled
    // earlier, otherwise, basepath separated from pathname with
    // separator, therefore lack of separator means partial
    // segment match (`/app` should not match `/application`)
    case normalizedPathname[normalizedBasepath.length] !== '/':
      return pathname

    // remove the basepath from the pathname if it starts with it
    case normalizedPathname.startsWith(normalizedBasepath):
      return pathname.slice(basepath.length)

    // otherwise, return the pathname as is
    default:
      return pathname
  }
}

export function matchByPath(
  basepath: string,
  from: string,
  matchLocation: Pick<MatchLocation, 'to' | 'caseSensitive' | 'fuzzy'>,
): Record<string, string> | undefined {
  // check basepath first
  if (basepath !== '/' && !from.startsWith(basepath)) {
    return undefined
  }
  // Remove the base path from the pathname
  from = removeBasepath(basepath, from, matchLocation.caseSensitive)
  // Default to to $ (wildcard)
  const to = removeBasepath(
    basepath,
    `${matchLocation.to ?? '$'}`,
    matchLocation.caseSensitive,
  )

  // Parse the from and to
  const baseSegments = parsePathname(from)
  const routeSegments = parsePathname(to)

  if (!from.startsWith('/')) {
    baseSegments.unshift({
      type: 'pathname',
      value: '/',
    })
  }

  if (!to.startsWith('/')) {
    routeSegments.unshift({
      type: 'pathname',
      value: '/',
    })
  }

  const params: Record<string, string> = {}

  const isMatch = (() => {
    let baseIndex = 0
    let routeIndex = 0

    while (
      baseIndex < baseSegments.length ||
      routeIndex < routeSegments.length
    ) {
      const baseSegment = baseSegments[baseIndex]
      const routeSegment = routeSegments[routeIndex]

      const isLastBaseSegment = baseIndex >= baseSegments.length - 1
      const isLastRouteSegment = routeIndex >= routeSegments.length - 1

      if (routeSegment) {
        if (routeSegment.type === 'wildcard') {
          // Capture all remaining segments for a wildcard
          const remainingBaseSegments = baseSegments.slice(baseIndex)

          let _splat: string

          // If this is a wildcard with prefix/suffix, we need to handle the first segment specially
          if (routeSegment.prefixSegment || routeSegment.suffixSegment) {
            if (!baseSegment) return false

            const prefix = routeSegment.prefixSegment || ''
            const suffix = routeSegment.suffixSegment || ''

            // Check if the base segment starts with prefix and ends with suffix
            const baseValue = baseSegment.value
            if ('prefixSegment' in routeSegment) {
              if (!baseValue.startsWith(prefix)) {
                return false
              }
            }
            if ('suffixSegment' in routeSegment) {
              if (
                !baseSegments[baseSegments.length - 1]?.value.endsWith(suffix)
              ) {
                return false
              }
            }

            let rejoinedSplat = decodeURI(
              joinPaths(remainingBaseSegments.map((d) => d.value)),
            )

            // Remove the prefix and suffix from the rejoined splat
            if (prefix && rejoinedSplat.startsWith(prefix)) {
              rejoinedSplat = rejoinedSplat.slice(prefix.length)
            }

            if (suffix && rejoinedSplat.endsWith(suffix)) {
              rejoinedSplat = rejoinedSplat.slice(
                0,
                rejoinedSplat.length - suffix.length,
              )
            }

            _splat = rejoinedSplat
          } else {
            // If no prefix/suffix, just rejoin the remaining segments
            _splat = decodeURI(
              joinPaths(remainingBaseSegments.map((d) => d.value)),
            )
          }

          // TODO: Deprecate *
          params['*'] = _splat
          params['_splat'] = _splat
          return true
        }

        if (routeSegment.type === 'pathname') {
          if (routeSegment.value === '/' && !baseSegment?.value) {
            routeIndex++
            continue
          }

          if (baseSegment) {
            if (matchLocation.caseSensitive) {
              if (routeSegment.value !== baseSegment.value) {
                return false
              }
            } else if (
              routeSegment.value.toLowerCase() !==
              baseSegment.value.toLowerCase()
            ) {
              return false
            }
            baseIndex++
            routeIndex++
            continue
          } else {
            return false
          }
        }

        if (routeSegment.type === 'param') {
          if (!baseSegment) {
            return false
          }

          if (baseSegment.value === '/') {
            return false
          }

          let _paramValue = ''
          let matched = false

          // If this param has prefix/suffix, we need to extract the actual parameter value
          if (routeSegment.prefixSegment || routeSegment.suffixSegment) {
            const prefix = routeSegment.prefixSegment || ''
            const suffix = routeSegment.suffixSegment || ''

            // Check if the base segment starts with prefix and ends with suffix
            const baseValue = baseSegment.value
            if (prefix && !baseValue.startsWith(prefix)) {
              return false
            }
            if (suffix && !baseValue.endsWith(suffix)) {
              return false
            }

            let paramValue = baseValue
            if (prefix && paramValue.startsWith(prefix)) {
              paramValue = paramValue.slice(prefix.length)
            }
            if (suffix && paramValue.endsWith(suffix)) {
              paramValue = paramValue.slice(
                0,
                paramValue.length - suffix.length,
              )
            }

            _paramValue = decodeURIComponent(paramValue)
            matched = true
          } else {
            // If no prefix/suffix, just decode the base segment value
            _paramValue = decodeURIComponent(baseSegment.value)
            matched = true
          }

          if (matched) {
            params[routeSegment.value.substring(1)] = _paramValue
            baseIndex++
          }

          routeIndex++
          continue
        }

        if (routeSegment.type === 'optional-param') {
          // Optional parameters can be missing - don't fail the match
          if (!baseSegment) {
            // No base segment for optional param - skip this route segment
            routeIndex++
            continue
          }

          if (baseSegment.value === '/') {
            // Skip slash segments for optional params
            routeIndex++
            continue
          }

          let _paramValue = ''
          let matched = false

          // If this optional param has prefix/suffix, we need to extract the actual parameter value
          if (routeSegment.prefixSegment || routeSegment.suffixSegment) {
            const prefix = routeSegment.prefixSegment || ''
            const suffix = routeSegment.suffixSegment || ''

            // Check if the base segment starts with prefix and ends with suffix
            const baseValue = baseSegment.value
            if (
              (!prefix || baseValue.startsWith(prefix)) &&
              (!suffix || baseValue.endsWith(suffix))
            ) {
              let paramValue = baseValue
              if (prefix && paramValue.startsWith(prefix)) {
                paramValue = paramValue.slice(prefix.length)
              }
              if (suffix && paramValue.endsWith(suffix)) {
                paramValue = paramValue.slice(
                  0,
                  paramValue.length - suffix.length,
                )
              }

              _paramValue = decodeURIComponent(paramValue)
              matched = true
            }
          } else {
            // For optional params without prefix/suffix, prefer skipping the optional
            // parameter if a later static pathname segment can match the current base segment.
            // This prevents optional params from "stealing" static segments (eg. matching
            // `/admin-levels/reports` against `/admin-levels/{-$id}/reports`).

            let shouldMatchOptional = true
            for (
              let lookAhead = routeIndex + 1;
              lookAhead < routeSegments.length;
              lookAhead++
            ) {
              const futureRouteSegment = routeSegments[lookAhead]

              if (
                futureRouteSegment?.type === 'pathname' &&
                futureRouteSegment.value !== '/' &&
                (matchLocation.caseSensitive
                  ? futureRouteSegment.value === baseSegment.value
                  : futureRouteSegment.value.toLowerCase() ===
                    baseSegment.value.toLowerCase())
              ) {
                // Ensure this future static segment can actually align by
                // "consuming" the optional param now.
                const remainingBaseSegments = baseSegments.slice(baseIndex + 1)
                const remainingRouteSegments = routeSegments.slice(lookAhead + 1)

                const canAlign = (() => {
                  let b = 0
                  let r = 0
                  while (r < remainingRouteSegments.length) {
                    const rs = remainingRouteSegments[r]!
                    const bs = remainingBaseSegments[b]

                    if (rs.type === 'pathname') {
                      if (rs.value === '/') {
                        r++
                        continue
                      }
                      if (!bs) return false
                      if (matchLocation.caseSensitive) {
                        if (rs.value !== bs.value) return false
                      } else if (rs.value.toLowerCase() !== bs.value.toLowerCase()) {
                        return false
                      }
                      b++
                      r++
                      continue
                    }

                    // stop if we hit a dynamic segment
                    return true
                  }
                  return true
                })()

                if (canAlign) {
                  shouldMatchOptional = false
                  break
                }
              }

              // Required params/wildcards are not skippable, so don't look past them.
              if (
                futureRouteSegment?.type === 'param' ||
                futureRouteSegment?.type === 'wildcard'
              ) {
                break
              }
            }

            if (shouldMatchOptional) {
              _paramValue = decodeURIComponent(baseSegment.value)
              matched = true
            }
          }

          if (matched) {
            params[routeSegment.value.substring(1)] = _paramValue
            baseIndex++
          }

          routeIndex++
          continue
        }
      }

      if (!isLastBaseSegment && isLastRouteSegment) {
        params['**'] = joinPaths(
          baseSegments.slice(baseIndex + 1).map((d) => d.value),
        )
        return !!matchLocation.fuzzy && routeSegment?.value !== '/'
      }

      // If we have base segments left but no route segments, it's not a match
      if (
        baseIndex < baseSegments.length &&
        routeIndex >= routeSegments.length
      ) {
        return false
      }

      // If we have route segments left but no base segments, check if remaining are optional
      if (
        routeIndex < routeSegments.length &&
        baseIndex >= baseSegments.length
      ) {
        // Check if all remaining route segments are optional
        for (let i = routeIndex; i < routeSegments.length; i++) {
          if (routeSegments[i]?.type !== 'optional-param') {
            return false
          }
        }
        // All remaining are optional, so we can finish
        break
      }

      break
    }

    return true
  })()

  return isMatch ? params : undefined
}

