      expect(result.routesById).toHaveProperty('/')
      expect(result.routesById).toHaveProperty('/about')
      expect(result.routesByPath).toHaveProperty('/')
      expect(result.routesByPath).toHaveProperty('/about')
      expect(result.flatRoutes).toHaveLength(2) // excludes root
    })

    it('should assign ranks to routes in flatRoutes', () => {
      const routeTree = createRouteTree(['/', '/about'])

      const result = processRouteTree({ routeTree })

      expect(result.flatRoutes[0]).toHaveProperty('rank', 0)
      expect(result.flatRoutes[1]).toHaveProperty('rank', 1)
    })
  })

  describe('route ranking - static segments vs params', () => {
    it('should prefer deeper static segments over earlier required params (optional-param vs required param)', () => {
      // This mirrors the reported file-based routing structure:
      // - `admin-levels/$adminlevelId/index.tsx`
      // - `admin-levels/{-$adminlevelId}/reports.tsx`
      // (index.tsx collapses to just `/admin-levels/$adminlevelId`)
      const routes = [
        '/admin-levels/$adminlevelId',
        '/admin-levels/{-$adminlevelId}/reports',
      ]

      const result = processRouteTree({ routeTree: createRouteTree(routes) })

      // The optional-param route should match with the param omitted:
      // `/admin-levels/reports` => `/admin-levels/{-$adminlevelId}/reports`
      const optionalRoute = result.flatRoutes.find(
        (d) => d.id === '/admin-levels/{-$adminlevelId}/reports',
      )!

      expect(
        getMatchedRoutes({
          pathname: '/admin-levels/reports',
          basepath: '/',
          caseSensitive: false,
          routesByPath: result.routesByPath,
          routesById: result.routesById,
          flatRoutes: [optionalRoute],
        }).foundRoute?.id,
      ).toBe('/admin-levels/{-$adminlevelId}/reports')

      // And when multiple routes match, the static `reports` segment should win
      // over the required param segment.
      const match = getMatchedRoutes({
        pathname: '/admin-levels/reports',
        basepath: '/',
        caseSensitive: false,
        routesByPath: result.routesByPath,
